class Solution(object):
    def resultingString(self, s):
        stack = []
        for c in s:
            if stack:
                diff = abs(ord(c) - ord(stack[-1]))
                if diff == 1 or diff == 25:  # consecutive or a-z wrap
                    stack.pop()
                    continue
            stack.append(c)
        return ''.join(stack)
